// PAGE STREAMING PUBLIC — /ecoute/:publicLinkId
// ─────────────────────────────────────────────
function PublicStreamPage() {
  const { publicLinkId } = useParams<{ publicLinkId: string }>();
  const [data, setData] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [showTitres, setShowTitres] = useState(false);
  const [dlOpen, setDlOpen] = useState(false);
  const [zikoState, setZikoState] = useState<'idle' | 'modal' | 'adding' | 'done'>('idle');
  const [showTutoCascade, setShowTutoCascade] = useState(false);

  // Déclencher tuto cascade après play
  // (déclenché depuis recordPublicStream)

  const recordPublicStream = async (track: string, duration: number) => {
    if (!data) return;
    try {
      await addDoc(collection(db, 'streams'), {
        publicLinkId, artist: data.artist || '', label: data.label || '',
        track, duration: Math.round(duration), valid: true,
        source: 'publicLink', ts: new Date().toISOString(),
      });
      if (data.artistEmail) {
        const qrSnap = await getDocs(query(collection(db, 'qrcodes'), where('artistEmail', '==', data.artistEmail), where('publicLinkId', '==', publicLinkId)));
        if (!qrSnap.empty) {
          await updateDoc(doc(db, 'qrcodes', qrSnap.docs[0].id), {
            streams: (qrSnap.docs[0].data().streams || 0) + 1,
          });
        }
      }
    } catch(e) { console.error('pubStream', e); }
    // Déclencher tuto cascade après premier play
    if (!localStorage.getItem('dz_tuto_seen_v4')) {
      setTimeout(() => setShowTutoCascade(true), 800);
    }
  };

  useEffect(() => {
    const load = async () => {
      const snap = await getDocs(query(collection(db, 'publicLinks'), where('publicLinkId', '==', publicLinkId)));
      if (!snap.empty) {
        const d = { id: snap.docs[0].id, ...snap.docs[0].data() } as any;
        setData(d);
        // Compter le Buzz — incrémenter visits
        try {
          await updateDoc(doc(db, 'publicLinks', snap.docs[0].id), { visits: (d.visits || 0) + 1 });
          // Aussi dans decouvrir si publié
          const dSnap = await getDocs(query(collection(db,'decouvrir'), where('publicLinkId','==',publicLinkId)));
          if (!dSnap.empty) await updateDoc(doc(db,'decouvrir',dSnap.docs[0].id),{ buzz:(dSnap.docs[0].data().buzz||0)+1 });
        } catch(e) { console.error('buzz',e); }
      }
      setLoading(false);
    };
    load();
  }, [publicLinkId]);

  const doAddToZiko = async (uid: string) => {
    if (!data) return;
    setZikoState('adding');
    try {
      const zikoData = {
        qrId: data.publicLinkId || publicLinkId,
        label: data.label || '',
        artist: data.artist || '',
        type: data.type || 'album',
        files: data.files || [],
        coverUrl: data.coverUrl || '',
        addedAt: new Date().toISOString(),
      };
      const existing = await getDocs(query(
        collection(db, 'zikotheque'),
        where('uid', '==', uid),
        where('qrId', '==', zikoData.qrId)
      ));
      if (existing.empty) {
        await addDoc(collection(db, 'zikotheque'), { uid, ...zikoData });
      }
      setZikoState('done');
    } catch(e) { console.error('ziko', e); setZikoState('idle'); }
  };

  const handleAddToZiko = async () => {
    const currentUser = auth.currentUser;
    if (currentUser) { await doAddToZiko(currentUser.uid); }
    else { setZikoState('modal'); }
  };

  if (loading) return (
    <div style={{ minHeight: '100vh', background: `${GLOW_TOP}, ${C.bgDeep}`, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <div style={{ width: 44, height: 44, border: '3px solid #1e6fff', borderTopColor: 'transparent', borderRadius: 99, animation: 'spin .8s linear infinite' }} />
    </div>
  );

  if (!data) return (
    <div style={{ minHeight: '100vh', background: `${GLOW_TOP}, ${C.bgDeep}`, display: 'flex', alignItems: 'center', justifyContent: 'center', color: C.text }}>
      <div style={{ textAlign: 'center' }}><p style={{ fontSize: 48, marginBottom: 12 }}>🎵</p><p style={{ color: '#4a5878' }}>Contenu non trouvé</p></div>
    </div>
  );

  const audioFiles = (data.files || []).filter((f: any) => f.name?.match(/\.(mp3|wav|aac|ogg|flac|m4a)$/i));
  const videoFiles = (data.files || []).filter((f: any) => f.name?.match(/\.(mp4|mov|avi|mkv|webm)$/i));

  return (
    <div style={{ minHeight: '100vh', background: `${GLOW_TOP}, ${C.bgDeep}`, color: C.text, fontFamily: "'DM Sans', sans-serif", paddingBottom: 40 }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=DM+Sans:wght@400;600;700&display=swap');
        @keyframes spin { to { transform: rotate(360deg) } }
        @keyframes fadeUp { from { opacity:0; transform:translateY(18px) } to { opacity:1; transform:translateY(0) } }
        .ps-row:hover { background: rgba(255,255,255,0.04) !important; }
      `}</style>

      {/* PUB MAISON */}

      {/* ── TUTO CASCADE — bulles après Play ── */}
      {showTutoCascade && <TutoCascade onDone={() => { setShowTutoCascade(false); localStorage.setItem('dz_tuto_seen_v4','1'); }} />}

      {/* ── POCHETTE — grande, visible, pleine largeur ── */}
      <div style={{ position: 'relative', width: '100%', animation: 'fadeUp .35s ease' }}>
        {data.coverUrl ? (
          <img
            src={data.coverUrl}
            alt={data.label}
            style={{ width: '100%', maxHeight: '60vh', objectFit: 'cover', display: 'block' }}
          />
        ) : (
          <div style={{ width: '100%', height: 260, background: 'linear-gradient(135deg,#0d1535,#1a3a6e)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <img src={LOGO_B64} alt="DZ" style={{ width: 100, opacity: 0.35 }} />
          </div>
        )}
        {/* dégradé bas */}
        <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 120, background: `linear-gradient(transparent, ${C.bgDeep})` }} />
      </div>

      {/* ── TITRE + ARTISTE ── */}
      <div style={{ padding: '0 18px', marginTop: -14, marginBottom: 22 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 26, fontWeight: 900, color: '#fff', marginBottom: 4, lineHeight: 1.1 }}>{data.label}</h1>
        <p style={{ color: '#6a88aa', fontSize: 13 }}>par <strong style={{ color: '#4da6ff' }}>{data.artist}</strong></p>
      </div>

      <div style={{ padding: '0 16px', maxWidth: 500, margin: '0 auto' }}>

        {/* ── LECTEUR AUDIO ── */}
        {audioFiles.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <AudioPlayer files={audioFiles} onStream={recordPublicStream}
              onDownload={() => setDlOpen(true)}
              onPlay={() => { if (!localStorage.getItem('dz_tuto_seen_v4')) setTimeout(() => setShowTutoCascade(true), 800); }} />
          </div>
        )}

        {/* ── BARRE ACTIONS — Kiff · Commenter · Kiffement · Buzz ── */}
        <ActionBar
          qrId={data.publicLinkId || publicLinkId || ''}
          artistEmail={data.artistEmail || ''}
          buzz={(data.visits||0)+(data.streams||0)}
          tutoStep={0}
          onTutoNext={() => {}}
        />
        <div id="zone-telecharger">
        {(() => {
          // QR privé (duplication) = totalScans défini ET pas de publicLinkId → téléchargement GRATUIT
          // QR public (lien partagé) → téléchargement PAYANT via AchatWidget
          const isPrivateQR = (data.totalScans > 0) && !data.publicLinkId;
          const dlsRestants = (data.totalScans || 0) - (data.usedScans || 0);
          const dlsEpuises = isPrivateQR && dlsRestants <= 0;

          if (isPrivateQR && !dlsEpuises) {
            // Téléchargement GRATUIT (QR privé)
            return (
              <div style={{ marginBottom: 20 }}>
                <a href={(data.files?.[0]?.url || '').replace('/upload/','/upload/fl_attachment/')} download target="_blank" rel="noreferrer"
                  style={{ width:'100%', boxSizing:'border-box', padding:'14px 18px', borderRadius:14, border:'none', background:'linear-gradient(135deg,'+C.blue+',#0050d0)', color:'#fff', fontWeight:800, fontSize:15, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:10, textDecoration:'none', boxShadow:'0 4px 18px rgba(10,132,255,0.45)' }}>
                  <span style={{ fontSize:18 }}>⬇</span>
                  Télécharger gratuitement
                </a>
                <p style={{ color:C.textSoft, fontSize:11, textAlign:'center', margin:'8px 0 0' }}>{dlsRestants} téléchargement{dlsRestants>1?'s':''} gratuit{dlsRestants>1?'s':''} restant{dlsRestants>1?'s':''}</p>
              </div>
            );
          }
          // Téléchargement PAYANT (QR public) — bouton masqué, ouvert depuis le lecteur
          return (data.price > 0 || data.files?.length > 0) && (
            <AchatWidget
              qrId={data.publicLinkId || publicLinkId || ''}
              albumLabel={data.label || ''}
              artistEmail={data.artistEmail || ''}
              prix={data.price || 0}
              files={data.files || []}
              hideButton={true}
              externalOpen={dlOpen}
              onExternalClose={() => setDlOpen(false)}
            />
          );
        })()}
        </div>

        {/* ── VIDÉOS ── */}
        {videoFiles.length > 0 && (
          <div style={{ marginBottom: 20 }}>
            <p style={{ color: '#4a5878', fontSize: 10, fontWeight: 700, letterSpacing: 2, marginBottom: 10, textTransform: 'uppercase' }}>Vidéos</p>
            <VideoPlayer files={videoFiles} onPlay={() => { if (!localStorage.getItem('dz_tuto_seen_v4')) setTimeout(() => setShowTutoCascade(true), 800); }} />
          </div>
        )}

        {/* ── TITRES (déroulant, discret) ── */}
        {(data.files || []).length > 1 && (
          <div style={{ marginBottom: 20 }}>
            <button onClick={() => setShowTitres(!showTitres)}
              style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'space-between', padding:'10px 14px', borderRadius:12, border:'1px solid '+C.border, background:'transparent', cursor:'pointer' }}>
              <span style={{ color: C.textSoft, fontSize: 12, fontWeight: 700, letterSpacing: 1, textTransform: 'uppercase' }}>Titres ({data.files.length})</span>
              <span style={{ color: C.textSoft, fontSize:15, transform: showTitres?'rotate(90deg)':'none', transition:'transform .2s' }}>›</span>
            </button>
            {showTitres && (
              <div style={{ marginTop: 8, background: 'rgba(20,28,48,0.5)', borderRadius: 14, overflow: 'hidden', border: '1px solid '+C.border }}>
                {data.files.map((f: any, i: number) => (
                  <div key={i} className="ps-row" style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '11px 16px', borderBottom: i < data.files.length - 1 ? '1px solid '+C.border : 'none' }}>
                    <div style={{ width: 32, height: 32, borderRadius: 8, background: 'linear-gradient(135deg,#0d1535,#1a3a6e)', display: 'flex', alignItems: 'center', justifyContent: 'center', flexShrink: 0 }}>
                      <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.5)" strokeWidth="2"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>
                    </div>
                    <div style={{ flex: 1, overflow: 'hidden' }}>
                      <p style={{ fontSize: 13, fontWeight: 600, color: C.text, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', margin: 0 }}>{f.name?.replace(/\.[^/.]+$/, '') || 'Piste ' + (i + 1)}</p>
                      <p style={{ color: C.textSoft, fontSize: 10, margin: '2px 0 0' }}>{formatSize(f.size || 0)}</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* ── AJOUTER À MA ZIKOTHÈQUE ── */}
        {zikoState === 'done' ? (
          <div style={{ display:'flex', alignItems:'center', gap:12, padding:'14px 16px', borderRadius:14, background:'rgba(30,200,100,0.1)', border:'1px solid rgba(30,200,100,0.3)', marginBottom:24 }}>
            <span style={{ fontSize:24 }}>✅</span>
            <div>
              <p style={{ fontWeight:700, fontSize:14, color:'#4dff9a', margin:0 }}>Ajouté à ta Zikothèque !</p>
              <a href="/ziko" style={{ color:'#4da6ff', fontSize:12, textDecoration:'none' }}>Voir ma Zikothèque →</a>
            </div>
          </div>
        ) : (
          <button onClick={handleAddToZiko} disabled={zikoState === 'adding'}
            style={{ width:'100%', padding:'15px 20px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#7c3aed,#4f46e5)', color:'#fff', fontWeight:700, fontSize:15, cursor: zikoState === 'adding' ? 'default' : 'pointer', display:'flex', alignItems:'center', gap:12, marginBottom:24, opacity: zikoState === 'adding' ? 0.7 : 1, boxShadow:'0 4px 20px rgba(124,58,237,0.4)' }}>
            <span style={{ fontSize:22, background:'rgba(255,255,255,0.15)', borderRadius:10, padding:'4px 8px' }}>
              {zikoState === 'adding' ? '⏳' : '➕'}
            </span>
            <div style={{ textAlign:'left' }}>
              <p style={{ margin:0, fontWeight:800 }}>{zikoState === 'adding' ? 'Ajout en cours...' : 'Ajouter à ma Zikothèque'}</p>
              <p style={{ margin:0, fontSize:11, opacity:0.7 }}>Retrouvez cet album à tout moment</p>
            </div>
          </button>
        )}

        {/* MODAL CONNEXION RAPIDE */}
        {zikoState === 'modal' && (
          <ZikoLoginModal
            onSuccess={(uid) => doAddToZiko(uid)}
            onClose={() => setZikoState('idle')}
          />
        )}

        {/* FOOTER */}
        <div style={{ textAlign: 'center' }}>
          <img src={LOGO_B64} alt="DZ" style={{ width: 36, opacity: 0.35, display: 'block', margin: '0 auto 6px' }} />
          <p style={{ color: 'rgba(100,140,200,0.2)', fontSize: 9, letterSpacing: 2, marginBottom: 14 }}>LA MUSIQUE. UN SCAN. UN MONDE.</p>
          <div style={{ display:'flex', gap:16, justifyContent:'center', flexWrap:'wrap', marginBottom:10 }}>
            <a href="/apropos" style={{ color:'#8098b8', fontSize:12, textDecoration:'none' }}>À propos</a>
            <a href="/conditions" style={{ color:'#8098b8', fontSize:12, textDecoration:'none' }}>Conditions d'utilisation</a>
            <a href="/privacy" style={{ color:'#8098b8', fontSize:12, textDecoration:'none' }}>Confidentialité</a>
          </div>
          <p style={{ color:'rgba(100,140,200,0.3)', fontSize:11 }}>© 2026 Doniel Zik — BDE SARL · Abidjan, Côte d'Ivoire</p>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// RETRAIT MODAL — méthodes de paiement
// ─────────────────────────────────────────────
function RetraitModal({ montant, oscart, artistEmail }: { montant:number, oscart:number, artistEmail:string }) {
  const [open, setOpen] = useState(false);
  const [methode, setMethode] = useState('');
  const [numero, setNumero] = useState('');
  const [iban, setIban] = useState('');
  const [sent, setSent] = useState(false);

  const METHODES = [
    { id:'wave', label:'Wave', icon:'📱', color:'#1a6bff' },
    { id:'orange', label:'Orange Money', icon:'📱', color:'#fb923c' },
    { id:'mtn', label:'MTN MoMo', icon:'📱', color:'#ffd700' },
    { id:'virement', label:'Virement bancaire', icon:'🏦', color:'#00c853' },
    { id:'visa', label:'Visa / Mastercard', icon:'💳', color:'#7c3aed' },
  ];

  const envoyer = async () => {
    if (!methode) return;
    await addDoc(collection(db,'retraits'), {
      artistEmail, montant, oscart, methode,
      numero: numero || iban,
      statut: 'en_attente',
      createdAt: new Date().toISOString(),
    });
    setSent(true);
  };

  if (!open) return (
    <button onClick={() => setOpen(true)} style={{ ...S.btn, padding:'8px 20px', fontSize:13 }}>
      Demander un retrait
    </button>
  );

  return (
    <>
      <button onClick={() => setOpen(true)} style={{ ...S.btn, padding:'8px 20px', fontSize:13 }}>
        Demander un retrait
      </button>
      <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.7)', zIndex:9990, display:'flex', alignItems:'flex-end', justifyContent:'center' }}
        onClick={() => setOpen(false)}>
        <div style={{ background:'#fff', borderRadius:'20px 20px 0 0', padding:'24px 24px 40px', width:'100%', maxWidth:480 }}
          onClick={e => e.stopPropagation()}>
          <div style={{ width:40, height:4, borderRadius:99, background:'#dce6f7', margin:'0 auto 20px' }} />
          {sent ? (
            <div style={{ textAlign:'center' }}>
              <p style={{ fontSize:40, marginBottom:12 }}>✅</p>
              <p style={{ fontWeight:800, fontSize:17, color:'#1a2340' }}>Demande envoyée !</p>
              <p style={{ color:'#8098b8', fontSize:13, marginTop:8 }}>
                Votre retrait de {montant.toLocaleString()} F CFA sera traité sous 72h via {methode}
              </p>
              <button onClick={() => { setOpen(false); setSent(false); }}
                style={{ ...S.btn, marginTop:20, width:'100%', padding:12 }}>Fermer</button>
            </div>
          ) : (
            <>
              <p style={{ fontWeight:800, fontSize:17, color:'#1a2340', marginBottom:4 }}>Demande de retrait</p>
              <p style={{ color:'#8098b8', fontSize:13, marginBottom:20 }}>{montant.toLocaleString()} F CFA = {oscart} Oscart</p>
              <p style={{ fontWeight:700, fontSize:13, color:'#1a2340', marginBottom:10 }}>Choisissez votre méthode</p>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:8, marginBottom:16 }}>
                {METHODES.map(m => (
                  <button key={m.id} onClick={() => setMethode(m.id)}
                    style={{ padding:'10px 8px', borderRadius:10, border:`2px solid ${methode===m.id?m.color:'#dce6f7'}`, background:methode===m.id?`${m.color}11`:'#fff', cursor:'pointer', textAlign:'center' }}>
                    <p style={{ fontSize:20, margin:'0 0 4px' }}>{m.icon}</p>
                    <p style={{ fontWeight:700, fontSize:12, color:methode===m.id?m.color:'#1a2340', margin:0 }}>{m.label}</p>
                  </button>
                ))}
              </div>
              {methode && methode !== 'virement' && (
                <div style={{ marginBottom:16 }}>
                  <label style={S.lbl}>Numéro {methode}</label>
                  <input style={S.inp} value={numero} onChange={e => setNumero(e.target.value)} placeholder="+225 07 00 00 00 00" />
                </div>
              )}
              {methode === 'virement' && (
                <div style={{ marginBottom:16 }}>
                  <label style={S.lbl}>IBAN</label>
                  <input style={S.inp} value={iban} onChange={e => setIban(e.target.value)} placeholder="FR76 3000 6000 0112 3456 7890 189" />
                </div>
              )}
              {methode === 'visa' && (
                <div style={{ marginBottom:16 }}>
                  <label style={S.lbl}>Numéro de carte (4 derniers chiffres)</label>
                  <input style={S.inp} value={numero} onChange={e => setNumero(e.target.value)} placeholder="**** **** **** 1234" />
                </div>
              )}
              <button onClick={envoyer} disabled={!methode}
                style={{ ...S.btn, width:'100%', padding:14, opacity:methode?1:0.5 }}>
                Confirmer la demande
              </button>
            </>
          )}
        </div>
      </div>
    </>
  );
}

